svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var ns          = 'http://www.w3.org/2000/svg';
    var dataLayerEl = svgEl.querySelector('#data-layer');
    var dotsL       = svgEl.querySelector('#dots-layer');
    var tipLayer    = svgEl.querySelector('#tip-layer');
    var defs        = svgEl.querySelector('defs');
    var clipRect    = svgEl.querySelector('#chartclip rect');

    var series = [
      { id:1, cls:'series-1', label:'Cyan',
        vals:[0,0,0,55,80,70,50,65], ys:[504.0,504.0,504.0,281.8,180.8,221.2,302.0,241.4] },
      { id:2, cls:'series-2', label:'Emerald',
        vals:[20,45,70,55,35,75,85,72], ys:[423.2,322.2,221.2,281.8,362.6,201.0,160.6,213.1] },
      { id:3, cls:'series-3', label:'Amber',
        vals:[0,30,55,80,60,40,0,0], ys:[504.0,382.8,281.8,180.8,261.6,342.4,504.0,504.0] },
      { id:4, cls:'series-4', label:'Rose',
        vals:[15,50,18,25,55,30,45,60], ys:[443.4,302.0,431.3,403.0,281.8,382.8,322.2,261.6] },
      { id:5, cls:'series-5', label:'Violet',
        vals:[55,25,23,26,24,27,22,25], ys:[281.8,403.0,411.1,399.0,407.0,394.9,415.1,403.0] },
    ];

    var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
    var xs   = [68,171,274,377,480,583,686,789];
    var allTips = {};
    var waveDelays = [0, 0.25, 0.50, 0.75, 1.00];
    var plotL = 42, plotR = 840, plotT = 100, plotB = 500;

    var el = ctx.el;

    function setHover(activeSid) {
      dataLayerEl.classList.add('hovering');
      series.forEach(function(s) {
        var wave = svgEl.querySelector('.wave-edge[data-series="'+s.id+'"]');
        var area = svgEl.querySelector('.area-fill[data-series="'+s.id+'"]');
        if (wave) wave.classList.remove('active');
        if (area) area.classList.remove('active');
        xs.forEach(function(_, qi) {
          var inner = svgEl.querySelector('#d'+s.id+'_'+qi+' .dot-inner');
          if (inner) inner.classList.remove('active');
        });
      });
      series.forEach(function(s) {
        var isActive = (s.id === activeSid);
        var wave = svgEl.querySelector('.wave-edge[data-series="'+s.id+'"]');
        var area = svgEl.querySelector('.area-fill[data-series="'+s.id+'"]');
        if (wave) wave.classList.toggle('active', isActive);
        if (area) area.classList.toggle('active', isActive);
        xs.forEach(function(_, qi) {
          var inner = svgEl.querySelector('#d'+s.id+'_'+qi+' .dot-inner');
          if (inner) inner.classList.toggle('active', isActive);
        });
      });
    }
    function clearHover() {
      dataLayerEl.classList.remove('hovering');
      series.forEach(function(s) {
        var wave = svgEl.querySelector('.wave-edge[data-series="'+s.id+'"]');
        var area = svgEl.querySelector('.area-fill[data-series="'+s.id+'"]');
        if (wave) wave.classList.remove('active');
        if (area) area.classList.remove('active');
        xs.forEach(function(_, qi) {
          var inner = svgEl.querySelector('#d'+s.id+'_'+qi+' .dot-inner');
          if (inner) inner.classList.remove('active');
        });
      });
    }

    series.forEach(function(s) {
      xs.forEach(function(x, qi) {
        var y=s.ys[qi], key=s.id+'_'+qi;
        var delay=((s.id-1)*0.25+qi*0.06)+'s';

        var dg=el('g',{'class':'dot-g',id:'d'+key});
        var inner=el('g',{'class':'dot-inner',style:'transform-origin:'+x+'px '+y+'px'});
        inner.classList.add('visible');
        var dot=el('circle',{cx:x,cy:y,r:5,'class':s.cls,stroke:'none'});
        inner.appendChild(dot); dg.appendChild(inner); dotsL.appendChild(dg);

        var tipG=el('g',{'class':'tip',id:'t'+key});
        tipLayer.appendChild(tipG); allTips[key]=tipG;
        ctx.layoutSideTooltip(tipG, {
          anchorX: x,
          anchorY: y,
          plotL: plotL,
          plotR: plotR,
          plotT: plotT,
          plotB: plotB,
          lines: [
            { text: '$'+s.vals[qi]+'M', className: 'tip-value' },
            { text: s.label+' - '+quarters[qi], className: 'tip-label' }
          ],
          lineHeights: [70, 70],
          minWidth: 220,
          paddingX: 20,
          paddingY: 30
        });

        var ch=svgEl.querySelector('#ch'+qi);
        dg.addEventListener('mouseenter',function(){
          allTips[key].style.opacity='1';
          if(ch) ch.style.opacity='1';
          dot.setAttribute('r','7');
          setHover(s.id);
        });
        dg.addEventListener('mouseleave',function(){
          allTips[key].style.opacity='';
          if(ch) ch.style.opacity='';
          dot.setAttribute('r','5');
          clearHover();
        });
      });
    });

    series.forEach(function(s, i) {
      var area = svgEl.querySelector('#area-' + s.id);
      if (!area) return;
      var areaClip = el('clipPath', { id:'area-reveal-' + s.id, clipPathUnits:'userSpaceOnUse' });
      var revealRect = el('rect', {
        x:clipRect.getAttribute('x'),
        y:clipRect.getAttribute('y'),
        width:clipRect.getAttribute('width'),
        height:clipRect.getAttribute('height')
      });
      revealRect.setAttribute('width', '0');
      areaClip.appendChild(revealRect);
      defs.appendChild(areaClip);
      area.setAttribute('clip-path', 'url(#area-reveal-' + s.id + ')');
      area.classList.add('visible');
      (function(rect, delay) {
        var startAt = performance.now() + delay * 1000;
        var duration = 1200;
        var fullWidth = parseFloat(clipRect.getAttribute('width'));
        function ease(t) {
          return 1 - Math.pow(1 - t, 3);
        }
        function tick(now) {
          if (now < startAt) {
            requestAnimationFrame(tick);
            return;
          }
          var p = Math.min((now - startAt) / duration, 1);
          rect.setAttribute('width', String(fullWidth * ease(p)));
          if (p < 1) requestAnimationFrame(tick);
        }
        requestAnimationFrame(tick);
      }(revealRect, waveDelays[i]));
    });

    /* wire animationend + .visible for wave-edges */
    var waveEls = svgEl.querySelectorAll('.wave-edge');
    waveEls.forEach(function(el, i) {
      el.style.animation = 'drawWave 1.2s cubic-bezier(0.4,0,0.2,1) ' + waveDelays[i] + 's';
      el.addEventListener('animationend', function() {
        el.style.animation = 'none';
        el.classList.add('visible');
      }, { once: true });
    });

    setTimeout(function() { dataLayerEl.classList.add('ready'); }, (1.00 + 1.2) * 1000 + 100);
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
